CREATE TABLE IF NOT EXISTS excellent_textbooks (
  id BIGINT NOT NULL AUTO_INCREMENT,
  external_textbook_id VARCHAR(128) NOT NULL,
  textbook_name VARCHAR(255) NOT NULL,
  chief_editor VARCHAR(255) NULL,
  category VARCHAR(64) NULL,
  publisher VARCHAR(255) NULL,
  publish_date VARCHAR(64) NULL,
  isbn VARCHAR(64) NULL,
  cover_url VARCHAR(1024) NULL,
  cover_file_path VARCHAR(512) NULL,
  description TEXT NULL,
  source_url VARCHAR(1024) NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uk_excellent_textbooks_external_id (external_textbook_id),
  KEY idx_excellent_textbooks_category (category)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

UPDATE learning_content_blocks
SET storage_folder = 'excellent_textbook'
WHERE block_code = 'textbooks';

ON DUPLICATE KEY UPDATE
  textbook_name = VALUES(textbook_name),
  chief_editor = VALUES(chief_editor),
  category = VALUES(category),
  publisher = VALUES(publisher),
  publish_date = VALUES(publish_date),
  isbn = VALUES(isbn),
  cover_url = VALUES(cover_url),
  cover_file_path = VALUES(cover_file_path),
  description = VALUES(description),
  source_url = VALUES(source_url);
